import { Component, OnInit, OnDestroy, ViewChild, ElementRef } from '@angular/core';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-candidate-dashboard',
  template: `
  <div class="page">
    <div class="page-header">
      <div>
        <h1 class="page-title">Candidate Dashboard</h1>
        <p class="muted" style="margin:0">{{auth.user?.email}}</p>
      </div>
      <button class="btn btn-black" (click)="logout()">Logout</button>
    </div>

    <div style="margin-top:18px">
      <div class="big-card-grid">
        <div class="big-card">
          <h2>Apply for Internship</h2>
          <p class="muted">Browse internships posted by HR and submit your application.</p>
          <div style="margin-top:12px">
            <button class="btn" (click)="router.navigate(['/candidate/internships'])">View Internships</button>
          </div>
        </div>

        <div class="big-card">
          <h2>View Applied Internships</h2>
          <p class="muted">See internships you've applied to and check interview details & results.</p>
          <div style="margin-top:12px">
            <button class="btn" (click)="router.navigate(['/candidate/applied'])">My Applications</button>
          </div>
        </div>
      </div>
    </div>
  </div>
  `
})
export class CandidateDashboardComponent implements OnInit, OnDestroy {
  internships: any[] = [];
  applications: any[] = [];
  selectedInternship: any = null;
  candidateName = '';
  phone = '';
  degree = '';
  college = '';
  cgpa = '';
  skills = '';
  resume: any = null;
  signedFiles: any = {};
  onboardingStatus: any = null;
  onboardingStatusMap: Record<string, any> = {};
  latestSignedOfferId: any = null;
  employee: any = null;
  candidateOnboardingForms: Record<string, any> = {};

  private intervalId: any;
  private pollingPaused = false;
  private refreshTimer: any;
  pickerAppId: any = null;
  @ViewChild('globalSignedInput') globalSignedInput!: ElementRef<HTMLInputElement>;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    if (!this.auth.user?.email) return;
    this.fetchInternships();
    this.fetchApplications();
    this.fetchEmployee();
    this.intervalId = setInterval(() => { if (!this.pollingPaused) { this.fetchApplications(); this.fetchOnboarding(); } }, 8000);
  }

  ngOnDestroy() { clearInterval(this.intervalId); }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  pausePolling() { this.pollingPaused = true; }

  resumePolling() { this.pollingPaused = false; }

  openSignedFilePicker(id: any) {
    this.pickerAppId = id;
    try { this.globalSignedInput.nativeElement.click(); } catch (err) { console.error('File picker open failed', err); }
  }

  onGlobalSignedSelected(e: any) {
    const file = e.target.files?.[0];
    if (!file) return;
    const isPdfMime = file.type && file.type.toLowerCase().includes('pdf');
    const isPdfExt = file.name && file.name.toLowerCase().endsWith('.pdf');
    if (!isPdfMime && !isPdfExt) { alert('Please select a PDF signed offer'); e.target.value = ''; return; }
    this.signedFiles = { ...this.signedFiles, [this.pickerAppId]: file };
    // clear the input so selecting same file again will fire change event next time
    e.target.value = '';
  }

  openOnboardingForm(appId: any) {
    const app = this.applications.find(a => a.id === appId);
    if (app && !app.signedOfferLetter) { return alert('Please upload the signed offer before filling onboarding'); }
    // navigate to the dedicated onboarding page and pass applicationId in navigation state
    this.router.navigate(['/onboarding'], { state: { applicationId: appId } });
  }

  cancelOnboardingForm(appId: any) {
    const copy = { ...this.candidateOnboardingForms };
    delete copy[appId];
    this.candidateOnboardingForms = copy;
    this.resumePolling();
  }

  async submitOnboarding(appId: any) {
    const payload = this.candidateOnboardingForms[appId];
    if (!payload) return;
    if (!payload.address || !payload.aadhaar || !payload.pan || !payload.bankAccount) return alert('Please fill all onboarding fields');
    try {
      await this.http.post('http://localhost:8080/api/onboarding', { ...payload, email: this.auth.user?.email, applicationId: appId }).toPromise();
      alert('Onboarding submitted successfully');
      // cleanup and refresh
      this.cancelOnboardingForm(appId);
      this.scheduleRefresh();
      this.latestSignedOfferId = appId;
      await this.fetchOnboardingFor(appId);
    } catch (err) {
      console.error(err);
      alert('Error submitting onboarding');
    }
  }

  scheduleRefresh(delay = 1000) {
    clearTimeout(this.refreshTimer);
    this.refreshTimer = setTimeout(() => {
      this.fetchApplications();
      this.fetchOnboarding();
      this.fetchEmployee();
    }, delay);
  }

  async fetchOnboarding() {
    // fetch onboarding for all signed applications
    const signedApps = this.applications.filter((a: any) => a.signedOfferLetter).map(a => a.id);
    await Promise.all(signedApps.map(id => this.fetchOnboardingFor(id)));
  }

  async fetchOnboardingFor(appId: any) {
    try {
      const res: any = await this.http.get(`http://localhost:8080/api/onboarding/application/${appId}`).toPromise();
      const status = res && res.length > 0 ? res[res.length - 1].status : null;
      this.onboardingStatusMap = { ...this.onboardingStatusMap, [appId]: status };
      return status;
    } catch (err) { console.error(err); this.onboardingStatusMap = { ...this.onboardingStatusMap, [appId]: null }; return null; }
  }

  getOnboardingStatus(app: any) {
    return this.onboardingStatusMap[app.id] || null;
  }

  async fetchEmployee() {
    if (!this.auth.user?.email) return;
    try { this.employee = await this.http.get(`http://localhost:8080/api/employees/${this.auth.user.email}`).toPromise(); } catch (err) { this.employee = null; }
  }

  async fetchInternships() { try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) { console.error(err); } }

  async fetchApplications() { try {
      const res: any = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise();
      const filtered = res.filter((app: any) => app.email === this.auth.user?.email);
      this.applications = filtered;
      const signed = filtered.filter((app: any) => app.signedOfferLetter).slice(-1)[0];
      this.latestSignedOfferId = signed?.id || null;
      this.fetchOnboarding();
    } catch (err) { console.error(err); }
  }

  hasApplied(internshipId: any) { return this.applications.some(app => app.internshipId === internshipId); }

  selectInternship(i: any) { this.selectedInternship = i; }

  onResumeSelected(e: any) { this.resume = e.target.files?.[0]; }

  async handleApply() {
    if (!this.resume) return alert('Please upload resume');
    const form = new FormData();
    form.append('internshipId', this.selectedInternship.id);
    form.append('candidateName', this.candidateName);
    form.append('email', this.auth.user?.email || '');
    form.append('phone', this.phone);
    form.append('degree', this.degree);
    form.append('college', this.college);
    form.append('cgpa', this.cgpa);
    form.append('skills', this.skills);
    form.append('resume', this.resume);
    await this.http.post('http://localhost:8080/api/applications/apply', form).toPromise();
    alert('Application submitted!');
    this.selectedInternship = null; this.candidateName = this.phone = this.degree = this.college = this.cgpa = this.skills = ''; this.resume = null; this.scheduleRefresh();
  }

  getInternship(app: any) { return this.internships.find(i => i.id === app.internshipId); }

  formatDate(dateString: any) { if (!dateString) return ''; return new Date(dateString).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }); }

  updateOfferStatus(id: any, status: string) { this.http.post('http://localhost:8080/api/applications/offer-status', null, { params: { applicationId: id, status } as any }).toPromise().then(() => this.fetchApplications()); }

  // legacy per-input handler (kept for compatibility but prefer global picker)
  onSignedOfferSelected(id: any, e: any) {
    const file = e.target.files?.[0];
    if (!file) return;
    const isPdfMime = file.type && file.type.toLowerCase().includes('pdf');
    const isPdfExt = file.name && file.name.toLowerCase().endsWith('.pdf');
    if (!isPdfMime && !isPdfExt) { alert('Please select a PDF signed offer'); return; }
    this.signedFiles = { ...this.signedFiles, [id]: file };
  }

  async uploadSignedOffer(id: any) {
    const file = this.signedFiles[id];
    if (!file) return alert('Upload signed offer');
    this.pausePolling();
    const y = window.scrollY || 0;
    try {
      const form = new FormData(); form.append('applicationId', id); form.append('file', file);
      const url = `http://localhost:8080/api/applications/upload-signed-offer`;
      const res: any = await this.http.post(url, form, { responseType: 'text' as 'json' }).toPromise();
      // if backend returns text filename, store it for UI
      if (typeof res === 'string' && res.trim()) {
        // mark uploaded file for the app
        this.applications = this.applications.map(a => a.id === id ? { ...a, signedOfferLetter: res } : a);
      } else {
        this.applications = this.applications.map(a => a.id === id ? { ...a, signedOfferLetter: true } : a);
      }
      alert('Signed offer uploaded');
      this.latestSignedOfferId = id;
      this.signedFiles = { ...this.signedFiles, [id]: null };
      this.scheduleRefresh();
      // navigate candidate to the dedicated onboarding page
      this.router.navigate(['/onboarding'], { state: { applicationId: id } });
    } catch (err) {
      console.error('Signed offer upload failed', err);
      alert('Error uploading signed offer');
    } finally {
      setTimeout(() => window.scrollTo(0, y), 0);
      this.resumePolling();
    }
  }

  // template now uses CSS classes; legacy style objects retained for compatibility but unused
